mapper.select:
SELECT id, consumer_group, event_id, topic, event_type, biz_key, consume_status,
       retry_count, error_message, consumed_at, created_at, updated_at
FROM bluenote_rank.rank_event_consume_log
WHERE consumer_group = #{consumerGroup}
  AND event_id = #{eventId}

mapper.update:
UPDATE bluenote_rank.rank_event_consume_log
SET consume_status = 'SUCCESS',
    consumed_at = NOW(3),
    updated_at = NOW(3)
WHERE consumer_group = #{consumerGroup}
  AND event_id = #{eventId}
